import json
import requests

# Function to create a virtual host
def create_vhost(name):
    url = "http://localhost:15672/api/vhosts/%s" % name
    payload = {
        "tracing": False,
        "ha-mode": "all",
        "message-ttl": 0,
        "auto-delete": False,
        "cluster-partition-handling": "pause-on-error"
    }
    headers = {
        'content-type': "application/json",
        'authorization': "Basic YWRtaW46cGFzc3dvcmQ="
    }
    response = requests.post(url, data=json.dumps(payload), headers=headers)
    return response.status_code == 201

# Function to create a user and grant permissions for queue operations
def create_user(username, password):
    url = "http://localhost:15672/api/users/%s" % username
    payload = {
        "password": password,
        "hash-password": True
    }
    headers = {
        'content-type': "application/json",
        'authorization': "Basic YWRtaW46cGFzc3dvcmQ="
    }
    response = requests.post(url, data=json.dumps(payload), headers=headers)
    if response.status_code == 201:
        # Grant permissions for queue operations
        url = "http://localhost:15672/api/permissions/%s" % username
        payload = {
            "configure": "*.*",
            "write": "*.*",
            "read": "*.*"
        }
        headers = {
            'content-type': "application/json",
            'authorization': "Basic YWRtaW46cGFzc3dvcmQ="
        }
        response = requests.put(url, data=json.dumps(payload), headers=headers)
        return response.status_code == 204
    else:
        return False

# Function to create a virtual host and user
def create_vhost_and_user(name, username, password):
    # Create a virtual host
    if not create_vhost(name):
        print("Error creating virtual host %s" % name)
        return False

    # Create a user and grant permissions for queue operations
    if not create_user(username, password):
        print("Error creating user %s" % username)
        return False

    # Grant permissions for queue operations on the virtual host
    url = "http://localhost:15672/api/permissions/%s/%s" % (name, username)
    payload = {
        "configure": "*.*",
        "write": "*.*",
        "read": "*.*"
    }
    headers = {
        'content-type': "application/json",
        'authorization': "Basic YWRtaW46cGFzc3dvcmQ="
    }
    response = requests.put(url, data=json.dumps(payload), headers=headers)
    return response.status_code == 204

# Main function
if __name__ == "__main__":
    # Create a virtual host and user for each application
    create_vhost_and_user("app1", "app1user", "password")
    create_vhost_and_user("app2", "app2user", "password")